2	export type Cell = [number, number];
3	
4	const isNeighborOf = ([x, y]: Cell, [nx, ny]: Cell): boolean =>
5	  Math.abs(nx - x) <= 1 && Math.abs(ny - y) <= 1 && !(nx === x && ny === y);
6	
7	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
8	  liveCells.filter((other) => isNeighborOf(cell, other)).length;
9	
10	const offsets = [-1, 0, 1];
11	
12	const neighborsOf = ([x, y]: Cell): Cell[] =>
13	  offsets
14	    .flatMap((dx) => offsets.map((dy): Cell => [x + dx, y + dy]))
15	    .filter(([nx, ny]) => !(nx === x && ny === y));
16	
17	const contains = (cells: Cell[], [x, y]: Cell): boolean =>
18	  cells.some(([cx, cy]) => cx === x && cy === y);
19	
20	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
21	  const survivors = liveCells.filter(
22	    (cell) => countLiveNeighbors(cell, liveCells) === 3,
23	  );
24	  const born = liveCells
25	    .flatMap(neighborsOf)
26	    .filter((cell) => !contains(liveCells, cell))
27	    .filter((cell) => countLiveNeighbors(cell, liveCells) === 3);
28	  const result = [...survivors];
29	  for (const cell of born) {
30	    if (!contains(result, cell)) {
31	      result.push(cell);
32	    }
33	  }
34	  return result;
35	};
